import { useEffect } from "react"

export default function Toast(props){
    useEffect(()=>{
        let toast = document.getElementById('toast');
        toast.className = 'show';
        setTimeout(() => {
            toast.className = toast.className.replace('show', '');
            props.controle(false);
        }, 3000);
    }, []);

    return(
        <div id='toast'>
            {props.mensagem}
        </div>
    )
}
